{"code": "import json
import re

# Get businesses and reviews
businesses = locals()['var_functions.query_db:22']

# Read the review data from file
review_file = locals()['var_functions.query_db:30']
if isinstance(review_file, str) and review_file.endswith('.json'):
    with open(review_file, 'r') as f:
        reviews = json.load(f)
else:
    reviews = review_file

# Extract businesses that accept credit cards
credit_card_businesses = []
for business in businesses:
    if business.get('attributes') != 'None' and business.get('attributes') is not None:
        attributes = business.get('attributes', {})
        if isinstance(attributes, dict) and attributes.get('BusinessAcceptsCreditCards') == 'True':
            # Extract numeric ID from business_id (format: businessid_XX)
            business_id_num = business['business_id'].split('_')[1]
            business['business_id_num'] = business_id_num
            credit_card_businesses.append(business)

# Extract categories from descriptions
category_count = {}
business_categories = {}

for business in credit_card_businesses:
    desc = business.get('description', '')

    # Find the category list portion
    cat_text = ""
    if "services in" in desc:
        cat_text = desc.split("services in")[1]
    elif "including" in desc:
        cat_text = desc.split("including")[1]
    elif "offers" in desc and "services" in desc:
        parts = desc.split("services")
        if len(parts) > 1:
            cat_text = parts[1]

    # Clean up the category text
    if cat_text:
        # Remove location info and trailing text
        cat_text = cat_text.split('.')[0]
        cat_text = cat_text.strip()

        # Extract individual categories
        categories = []
        if ',' in cat_text:
            # Split by comma
            parts = cat_text.split(',')
            for part in parts:
                part = part.strip()
                # Handle "and" at the beginning or end
                if part.startswith('and '):
                    part = part[4:]
                if part.endswith(' and'):
                    part = part[:-4]
                if part and part != 'and':
                    categories.append(part)
        else:
            # Single category
            categories = [cat_text.strip()]

        # Clean categories (remove empty, remove "and")
        cleaned_cats = [cat for cat in categories if cat and cat != 'and']

        business_categories[business['business_id_num']] = cleaned_cats

        # Count categories
        for cat in cleaned_cats:
            category_count[cat] = category_count.get(cat, 0) + 1

print('__RESULT__:')
print(json.dumps({
    "credit_card_businesses": len(credit_card_businesses),
    "category_count": category_count,
    "business_categories": business_categories
}))"}

