{"code": "import json
import re
import os

# Get the review data file
review_file = locals()['var_functions.query_db:30']

# Load all reviews
if isinstance(review_file, str) and review_file.endswith('.json'):
    with open(review_file, 'r') as f:
        reviews = json.load(f)
else:
    reviews = locals()['var_functions.query_db:30']

# Get businesses from the full query
businesses = locals()['var_functions.query_db:46']

# Filter for businesses that accept credit cards
credit_card_businesses = []
for business in businesses:
    attrs = business.get('attributes')
    if attrs != 'None' and attrs is not None:
        if isinstance(attrs, dict) and attrs.get('BusinessAcceptsCreditCards') == 'True':
            # Extract business ID number
            biz_id = business['business_id'].split('_')[1]
            business['biz_id_num'] = biz_id
            credit_card_businesses.append(business)

# Extract categories for each credit card business
category_business_map = {}
for business in credit_card_businesses:
    desc = business.get('description', '')
    biz_id = business['biz_id_num']

    # Extract category portion
    cat_text = ""
    if "services in" in desc:
        cat_text = desc.split("services in")[1]
    elif "including" in desc:
        cat_text = desc.split("including")[1]
    elif "offers" in desc and "services" in desc:
        parts = desc.split("services")
        if len(parts) > 1:
            cat_text = parts[1]

    # Clean and split categories
    categories = []
    if cat_text:
        cat_text = cat_text.split('.')[0].strip()

        # Handle comma separation
        if ',' in cat_text:
            parts = cat_text.split(',')
            for part in parts:
                part = part.strip()
                # Clean "and" prefixes/suffixes
                if part.startswith('and '):
                    part = part[4:]
                if part.endswith(' and'):
                    part = part[:-4]
                if part and part != 'and':
                    # Fix the malformed "including Nail Salons"
                    if part.startswith('cluding '):
                        part = part[8:]  # Remove "cluding "
                    categories.append(part)
        else:
            # Single category
            cat = cat_text.strip()
            if cat.startswith('cluding '):
                cat = cat[8:]
            if cat:
                categories.append(cat)

    business['categories'] = categories

    # Map categories to business IDs
    for cat in categories:
        if cat not in category_business_map:
            category_business_map[cat] = []
        category_business_map[cat].append(biz_id)

# Find the category with most businesses
max_category = None
max_count = 0
for cat, biz_list in category_business_map.items():
    if len(biz_list) > max_count:
        max_count = len(biz_list)
        max_category = cat

# Get ratings for the max category
max_business_ids = category_business_map.get(max_category, [])
rating_sum = 0
rating_count = 0

for review in reviews:
    business_ref = review.get('business_ref', '')
    if business_ref:
        # Extract business ID number from business_ref (format: businessref_XX)
        ref_id_num = business_ref.split('_')[1]
        if ref_id_num in max_business_ids:
            rating = int(review.get('rating', 0))
            rating_sum += rating
            rating_count += 1

# Calculate average rating
avg_rating = rating_sum / rating_count if rating_count > 0 else 0

print('__RESULT__:')
print(json.dumps({
    "max_category": max_category,
    "business_count_in_category": max_count,
    "average_rating": round(avg_rating, 2),
    "category_business_map": category_business_map
}))"}

